INSERT INTO `wp_posts` VALUES (2,1,'2017-05-19 07:15:33','2017-05-19 07:15:33','Đây là một trang tĩnh mẫu. Nó khác với một bài viết ở chỗ nó sẽ luôn ở một vị trí và sẽ được hiển thị tại thực đơn điều hướng trên trang mạng của bạn (với hầu hết các giao diện). Hầu hết mọi người bắt đầu với trang Giới Thiệu kể về họ với người đọc. Nó có thể được viết như sau:\n\n<blockquote>Xin chào! tôi là người chuyển hàng bằng xe đạp vào ban ngày, diễn viên luôn nỗ lực tiến bộ vào buổi tối, và đây là trang nhật ký trực tuyến của tôi. Tôi sống ở Los Angeles, tôi nuôi một con chó tuyệt vời tên là Jack, và tôi thích pi&#241;a coladas. (Và có thể gặp trong mưa.)</blockquote>\n\n...hoặc tương tự như:\n\n<blockquote>Công ty Đồ dùng XYZ được thành lập năm 1971, và đã cung cấp đồ dùng chất lượng cho cộng đồng từ thời điểm đó. Tại thành phố Gotham, XYZ tạo ra việc làm cho hơn 2,000 người và làm ra những đồ dùng tuyệt vời phục vụ mọi nhu cầu cho người dân Gotham.</blockquote>\n\nLà một người sử dụng WordPress mới, bạn nên truy cập <a href=\"http://localhost:8080/wp-admin/\">bảng thống kê</a> để xóa trang tĩnh này và tạo trang tĩnh mới cho nội dung của bạn. Hãy tận hưởng!','Trang Mẫu','','publish','closed','open','','Trang mẫu','','','2017-05-19 07:15:33','2017-05-19 07:15:33','',0,'http://localhost:8080/?page_id=2',0,'page','',0),(5,1,'2017-05-19 07:18:10','2017-05-19 07:18:10','<label> Your Name (required)\n    [text* your-name] </label>\n\n<label> Your Email (required)\n    [email* your-email] </label>\n\n<label> Subject\n    [text your-subject] </label>\n\n<label> Your Message\n    [textarea your-message] </label>\n\n[submit \"Send\"]\nTrang web mới \"[your-subject]\"\n[your-name] <admin@admin.com>\nFrom: [your-name] <[your-email]>\nSubject: [your-subject]\n\nMessage Body:\n[your-message]\n\n-- \nThis e-mail was sent from a contact form on Trang web mới (http://localhost:8080)\nadmin@admin.com\nReply-To: [your-email]\n\n0\n0\n\nTrang web mới \"[your-subject]\"\nTrang web mới <admin@admin.com>\nMessage Body:\n[your-message]\n\n-- \nThis e-mail was sent from a contact form on Trang web mới (http://localhost:8080)\n[your-email]\nReply-To: admin@admin.com\n\n0\n0\nThank you for your message. It has been sent.\nThere was an error trying to send your message. Please try again later.\nOne or more fields have an error. Please check and try again.\nThere was an error trying to send your message. Please try again later.\nYou must accept the terms and conditions before sending your message.\nThe field is required.\nThe field is too long.\nThe field is too short.','Contact form 1','','publish','closed','closed','','contact-form-1','','','2017-05-19 07:18:10','2017-05-19 07:18:10','',0,'http://localhost:8080/?post_type=wpcf7_contact_form&p=5',0,'wpcf7_contact_form','',0),(6,1,'2017-05-19 07:19:52','2017-05-19 07:19:52','[yith_wcwl_wishlist]','Wishlist','','publish','closed','closed','','wishlist','','','2017-05-19 07:19:52','2017-05-19 07:19:52','',0,'http://localhost:8080/wishlist/',0,'page','',0),(10,1,'2017-05-19 07:30:53','2017-05-19 07:30:53','','Cửa hàng','','publish','closed','closed','','cua-hang','','','2017-05-24 01:18:53','2017-05-24 01:18:53','',0,'http://localhost:8080/cua-hang/',0,'page','',0),(11,1,'2017-05-19 07:30:53','2017-05-19 07:30:53','[woocommerce_cart]','Giỏ hàng','','publish','closed','closed','','gio-hang','','','2017-05-19 07:30:53','2017-05-19 07:30:53','',0,'http://localhost:8080/gio-hang/',0,'page','',0),(12,1,'2017-05-19 07:30:53','2017-05-19 07:30:53','[woocommerce_checkout]','Thanh toán','','publish','closed','closed','','thanh-toan','','','2017-05-19 07:30:53','2017-05-19 07:30:53','',0,'http://localhost:8080/thanh-toan/',0,'page','',0),(13,1,'2017-05-19 07:30:53','2017-05-19 07:30:53','[woocommerce_my_account]','My account','','publish','closed','closed','','tai-khoan','','','2017-05-19 07:30:53','2017-05-19 07:30:53','',0,'http://localhost:8080/tai-khoan/',0,'page','',0),(163,1,'2017-05-23 08:33:12','2017-05-23 08:33:12','[sect